#!/bin/bash\n\n# InsureXThon Azure Deployment Script (Bash)\n# This script automates the complete Azure setup\n\nset -e\n\n# Configuration\nSUBSCRIPTION_ID=\"${1:-}\"\nRESOURCE_GROUP=\"${2:-rg-insurexthon}\"\nLOCATION=\"${3:-eastus}\"\nAPP_NAME=\"${4:-insurexthon}\"\nENVIRONMENT=\"${5:-prod}\"\n\n# Colors\nRED='\\033[0;31m'\nGREEN='\\033[0;32m'\nYELLOW='\\033[1;33m'\nBLUE='\\033[0;34m'\nNC='\\033[0m' # No Color\n\n# Helper functions\necho_header() {\n    echo -e \"\\n${BLUE}=== $1 ===${NC}\"\n}\n\necho_success() {\n    echo -e \"${GREEN}✓ $1${NC}\"\n}\n\necho_error() {\n    echo -e \"${RED}✗ $1${NC}\"\n}\n\necho_warning() {\n    echo -e \"${YELLOW}⚠ $1${NC}\"\n}\n\n# Check prerequisites\necho_header \"Checking Prerequisites\"\n\nif ! command -v az &> /dev/null; then\n    echo_error \"Azure CLI not found. Install from: https://docs.microsoft.com/en-us/cli/azure/install-azure-cli\"\n    exit 1\nfi\necho_success \"Azure CLI found\"\n\nif ! command -v git &> /dev/null; then\n    echo_error \"Git not found\"\n    exit 1\nfi\necho_success \"Git found\"\n\n# Authenticate\necho_header \"Step 1: Azure Authentication\"\n\nCURRENT_ACCOUNT=$(az account show --query \"id\" -o tsv 2>/dev/null || true)\n\nif [ -z \"$CURRENT_ACCOUNT\" ]; then\n    echo \"Logging in to Azure...\"\n    az login\nfi\n\nif [ -n \"$SUBSCRIPTION_ID\" ]; then\n    az account set --subscription \"$SUBSCRIPTION_ID\"\n    echo_success \"Set subscription to $SUBSCRIPTION_ID\"\nelse\n    SUBSCRIPTION_ID=$(az account show --query \"id\" -o tsv)\n    echo_success \"Using current subscription: $SUBSCRIPTION_ID\"\nfi\n\n# Create Resource Group\necho_header \"Step 2: Create Resource Group\"\n\nRG_EXISTS=$(az group exists --name \"$RESOURCE_GROUP\" --query \"value\" -o tsv)\n\nif [ \"$RG_EXISTS\" == \"true\" ]; then\n    echo_warning \"Resource group '$RESOURCE_GROUP' already exists\"\nelse\n    az group create --name \"$RESOURCE_GROUP\" --location \"$LOCATION\"\n    echo_success \"Created resource group: $RESOURCE_GROUP\"\nfi\n\n# Create Entra ID App\necho_header \"Step 3: Create Entra ID App Registration\"\n\nAPP_DISPLAY_NAME=\"$APP_NAME-api\"\nEXISTING_APP=$(az ad app list --filter \"displayName eq '$APP_DISPLAY_NAME'\" --query \"[0].appId\" -o tsv 2>/dev/null || true)\n\nif [ -n \"$EXISTING_APP\" ]; then\n    echo_warning \"App registration '$APP_DISPLAY_NAME' already exists: $EXISTING_APP\"\n    APP_ID=\"$EXISTING_APP\"\nelse\n    APP_ID=$(az ad app create --display-name \"$APP_DISPLAY_NAME\" --query \"appId\" -o tsv)\n    echo_success \"Created app registration: $APP_ID\"\nfi\n\n# Create client secret\nCLIENT_SECRET=$(az ad app credential create --id \"$APP_ID\" --years 2 --query \"password\" -o tsv)\necho_success \"Created client secret (valid 2 years)\"\necho_warning \"Save this client secret securely: $CLIENT_SECRET\"\n\n# Create Key Vault\necho_header \"Step 4: Create Azure Key Vault\"\n\nKV_NAME=\"kv-$APP_NAME\"\nKV_EXISTS=$(az keyvault list --query \"[?name=='$KV_NAME'].name\" -o tsv 2>/dev/null || true)\n\nif [ -n \"$KV_EXISTS\" ]; then\n    echo_warning \"Key vault '$KV_NAME' already exists\"\nelse\n    az keyvault create --resource-group \"$RESOURCE_GROUP\" --name \"$KV_NAME\" --location \"$LOCATION\" || echo_warning \"Key vault creation skipped (may already exist)\"\n    echo_success \"Created Key Vault: $KV_NAME\"\nfi\n\n# Deploy Bicep\necho_header \"Step 5: Deploy Infrastructure (Bicep)\"\n\nif [ ! -f \"infra/main.bicep\" ]; then\n    echo_error \"infra/main.bicep not found. Please ensure you're in the repository root.\"\n    exit 1\nfi\n\necho \"Validating Bicep template...\"\naz deployment group validate \\\n    --resource-group \"$RESOURCE_GROUP\" \\\n    --template-file \"infra/main.bicep\" \\\n    --parameters appName=\"$APP_NAME\" location=\"$LOCATION\" environment=\"$ENVIRONMENT\" > /dev/null\n\necho_success \"Bicep template validation passed\"\n\necho \"Deploying infrastructure (this may take 5-10 minutes)...\"\naz deployment group create \\\n    --resource-group \"$RESOURCE_GROUP\" \\\n    --template-file \"infra/main.bicep\" \\\n    --parameters appName=\"$APP_NAME\" location=\"$LOCATION\" environment=\"$ENVIRONMENT\" \\\n    --output none\n\necho_success \"Infrastructure deployment completed\"\n\n# Get outputs\necho_header \"Step 6: Deployment Outputs\"\n\nOUTPUTS=$(az deployment group show \\\n    --resource-group \"$RESOURCE_GROUP\" \\\n    --name main \\\n    --query \"properties.outputs\" -o json)\n\necho \"$OUTPUTS\" | jq . || echo \"$OUTPUTS\"\n\n# Verify\necho_header \"Step 7: Verify Deployment\"\n\nRESOURCE_COUNT=$(az resource list --resource-group \"$RESOURCE_GROUP\" --query \"length(@)\" -o tsv)\necho_success \"Created $RESOURCE_COUNT resources in $RESOURCE_GROUP\"\n\necho \"\\nCreated Resources:\"\naz resource list --resource-group \"$RESOURCE_GROUP\" --query \"[].{Name:name, Type:type}\" -o table\n\n# GitHub Secrets\necho_header \"Step 8: GitHub Secrets Configuration\"\n\nTENANT_ID=$(az account show --query \"tenantId\" -o tsv)\n\necho_warning \"Please add these secrets to your GitHub repository:\"\necho \"GitHub Repo: https://github.com/AkshayUsha/Create-a-WeCAT-Portfolio-Stress-Test-Reinsurance-Placement-Optimiser\"\necho \"Path: Settings → Secrets and variables → Actions → New repository secret\"\necho \"\"\n\necho \"1. AZURE_CREDENTIALS (JSON format):\"\necho \"{\"\necho \"  \\\"clientId\\\": \\\"$APP_ID\\\",\"\necho \"  \\\"clientSecret\\\": \\\"$CLIENT_SECRET\\\",\"\necho \"  \\\"subscriptionId\\\": \\\"$SUBSCRIPTION_ID\\\",\"\necho \"  \\\"tenantId\\\": \\\"$TENANT_ID\\\"\"\necho \"}\"\necho \"\"\n\necho \"2. AZURE_SUBSCRIPTION_ID: $SUBSCRIPTION_ID\"\necho \"3. AZURE_TENANT_ID: $TENANT_ID\"\necho \"4. AZURE_CLIENT_ID: $APP_ID\"\necho \"5. AZURE_CLIENT_SECRET: $CLIENT_SECRET\"\necho \"6. AZURE_RESOURCE_GROUP: $RESOURCE_GROUP\"\necho \"7. AZURE_APP_SERVICE_NAME: $APP_NAME-api\"\necho \"8. AZURE_STATIC_WEB_APP_NAME: $APP_NAME-web\"\necho \"9. AZURE_OPENAI_API_KEY: <your-openai-key>\"\necho \"10. AZURE_OPENAI_ENDPOINT: <your-openai-endpoint>\"\necho \"\"\n\n# Summary\necho_header \"Deployment Complete!\"\necho_success \"Your Azure infrastructure is ready for deployment\"\n\necho \"\"\necho \"Next steps:\"\necho \"1. Configure GitHub secrets (see above)\"\necho \"2. Push code to main branch to trigger CI/CD\"\necho \"3. Monitor deployment in GitHub Actions\"\necho \"4. Verify endpoints are accessible\"\necho \"\"\necho \"Useful commands:\"\necho \"  # View logs\"\necho \"  az webapp log tail --resource-group $RESOURCE_GROUP --name $APP_NAME-api\"\necho \"\"\necho \"  # Check health\"\necho \"  curl https://$APP_NAME-api.azurewebsites.net/health\"\necho \"\"\necho \"  # View resources\"\necho \"  az resource list --resource-group $RESOURCE_GROUP -o table\"\necho \"\"\n"